// C-like pseudocode for Unix process creation
PROCEDURE CreateProcess(programName, arguments)
BEGIN
    // fork() creates child process
    pid = fork()

    IF pid == 0 THEN
        // This is child process
        // Replace child image with new program
        exec(programName, arguments)
        // If exec returns, it failed
        PRINT "Exec failed"
        EXIT
    ELSE IF pid > 0 THEN
        // This is parent process
        // Parent continues execution
        PRINT "Child created with PID: ", pid
        // Wait for child to complete
        wait(pid)
    ELSE
        // fork() failed
        PRINT "Fork failed"
    END IF
END

#include <stdio.h>
#include <stdlib.h>

// Process Control Block Structure
typedef struct {
    int pid;                    // Process ID
    int parent_pid;             // Parent Process ID
    char state;                 // 'N'=New, 'R'=Ready, 'S'=Running, 'W'=Waiting, 'T'=Terminated
    unsigned int pc;            // Program Counter
    unsigned int registers[16]; // CPU Registers
    unsigned int priority;      // Scheduling priority
    unsigned int cpu_time_used; // CPU time consumed
    unsigned int memory_limit;  // Memory allocation limit
    void *heap_base;            // Base address of heap
    void *stack_base;           // Base address of stack
} ProcessControlBlock;

// Function to create and initialize PCB
ProcessControlBlock* create_pcb(int pid, int parent_pid) {
    ProcessControlBlock *pcb = (ProcessControlBlock*)malloc(sizeof(ProcessControlBlock));
    pcb->pid = pid;
    pcb->parent_pid = parent_pid;
    pcb->state = 'N';  // New state
    pcb->pc = 0;
    pcb->priority = 10;  // Default priority
    pcb->cpu_time_used = 0;
    return pcb;
}

int main() {
    ProcessControlBlock *pcb = create_pcb(1000, 1);
    printf("PCB Created - PID: %d, State: %c\n", pcb->pid, pcb->state);
    return 0;
}
